module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [2:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] mul_out_reg;
reg [15:0] temp[0:7];
reg [15:0] sum[0:3];
integer i;
always@(posedge clk or negedge rst_n)begin
	if(!rst_n)begin
		mul_en_out_reg <= 0;
	end
	else begin
		mul_en_out_reg <= {mul_en_out_reg[1:0],mul_en_in};
	end
end
always@(posedge clk)begin
	if(mul_en_in)begin
		mul_a_reg <= mul_a;
		mul_b_reg <= mul_b;
	end
	else begin
		mul_a_reg <= 0;
		mul_b_reg <= 0;
	end
end
always@(*)begin
	temp[0] = mul_a_reg[0]?{8'b0,mul_b_reg}:0;
	temp[1] = mul_a_reg[1]?{7'b0,mul_b_reg,1'b0}:0;
	temp[2] = mul_a_reg[2]?{6'b0,mul_b_reg,2'b0}:0;
	temp[3] = mul_a_reg[3]?{5'b0,mul_b_reg,3'b0}:0;
	temp[4] = mul_a_reg[4]?{4'b0,mul_b_reg,4'b0}:0;
	temp[5] = mul_a_reg[5]?{3'b0,mul_b_reg,5'b0}:0;
	temp[6] = mul_a_reg[6]?{2'b0,mul_b_reg,6'b0}:0;
	temp[7] = mul_a_reg[7]?{1'b0,mul_b_reg,7'b0}:0;
end
always@(posedge clk)begin
	sum[0] <= temp[0]+temp[1];
	sum[1] <= temp[2]+temp[3];
	sum[2] <= temp[4]+temp[5];
	sum[3] <= temp[6]+temp[7];
end
always@(posedge clk)begin
	mul_out_reg <= sum[0]+sum[1]+sum[2]+sum[3];
end
assign mul_en_out = mul_en_out_reg[2];
assign mul_out = mul_en_out?mul_out_reg:0;
endmodule
